import numpy as np
import heapq

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    if len(unvisited_nodes) == 0:
        return depot_node

    priority_queue = []

    average_distance_vector = np.mean(distance_matrix[unvisited_nodes, :], axis=0)
    distance_variance_vector = np.var(distance_matrix[unvisited_nodes, :], axis=0)

    for node in unvisited_nodes:
        if node in truck_nodes:
            continue

        distance_to_node = distance_matrix[current_node, node]
        variance_score = distance_variance_vector[node]

        score = distance_to_node - variance_score
        heapq.heappush(priority_queue, (score, node))

    if priority_queue:
        _, next_node = heapq.heappop(priority_queue)
        return next_node
    else:
        return next_node

