import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node by evaluating clusters of unvisited nodes, prioritizing smaller clusters 
    (hubs of proximity) and within each cluster picking the nearest node, as a way to efficiently cover nodes with minimal 
    waiting, or returns to the depot if all clusters are visited or inactive.}
    """
    def find_clusters(nodes, max_distance):
        visited = set()
        clusters = []

        def dfs(node, cluster):
            for other in nodes:
                if other not in visited and distance_matrix[node, other] <= max_distance:
                    visited.add(other)
                    cluster.append(other)
                    dfs(other, cluster)

        for node in nodes:
            if node not in visited:
                cluster = []
                dfs(node, cluster)
                if cluster:
                    clusters.append(cluster)

        return clusters

    if len(unvisited_nodes) == 0:
        return depot_node

    # Define a threshold distance to determine what constitutes a cluster
    threshold_distance = np.min(distance_matrix[distance_matrix > 0]) * 1.5
    clusters = find_clusters(unvisited_nodes, threshold_distance)

    if not clusters:
        return depot_node

    # Select the smallest cluster in terms of the number of nodes
    clusters.sort(key=len)
    chosen_cluster = clusters[0]

    # Within the chosen cluster, find the nearest node to the current node
    closest_node = None
    min_distance = float('inf')
    for node in chosen_cluster:
        if node in truck_nodes:
            continue
        distance = distance_matrix[current_node, node]
        if distance < min_distance:
            min_distance = distance
            closest_node = node

    if closest_node is not None:
        return closest_node

    return next_node
